import {useState } from 'react';
import { connect } from 'react-redux';
import { incrementCoutner, changeCounterStep } from '../../actions/counterActions';
import { fetchStarWarsCharacter } from '../../actions/starwarsActions';

const Counter = ({
    fetchStarWarsCharacter,
    changeCounterStep,
    incrementCoutner,
    countNumber,
    message,
}) => {
    const [step, setStep] = useState(1);

    const stepChangeHandler = e => {
        let stepValue = Number(e.target.value);

        setStep(stepValue);
    }

    return (
        <div>
            <h1>Counter Page</h1>
            <h2>{message}</h2>
            <div>{countNumber}</div>
            <button onClick={e => incrementCoutner()}>Increment</button>
            <button onClick={e => changeCounterStep(step)}>Change Step</button>
            <button onClick={e => fetchStarWarsCharacter(step)}>Fetch StarWars Character</button>
            <select onChange={stepChangeHandler}>
                <option value="1">1</option>
                <option value="2">2</option>
                <option value="3">3</option>
                <option value="4">4</option>
            </select>
        </div>
    );
};

const mapStateToProps = state => ({
    countNumber: state.counter.counter,
    message: 'hello from counter'
});

// const mapDispatchToProps = dispatch => ({
//     increment: () => dispatch(incrementCoutner()),
//     changeStep: (step) => dispatch(changeCounterStep(step))
// });

const mapDispatchToProps = {
    incrementCoutner,
    changeCounterStep,
    fetchStarWarsCharacter,
};

// let hoc = connect(mapStateToProps, mapDispatchToProps);
export default connect(mapStateToProps, mapDispatchToProps)(Counter);

