import { useState, useEffect } from 'react';

const useFetch = (url) => {
    const [state, setState] = useState({data: null, isLoading: true});

    useEffect(() => {
        setState(currentState => ({...currentState, isLoading: true}));

        fetch(url)
            .then(res => res.json())
            .then(data => {
                setState({data, isLoading: false});
            });
    }, [url]);

    return state;
}

export default useFetch;