const initialState = {
    counter: 0,
    step: 1, 
};

const counter = (state = initialState, action) => {
    switch (action.type) {
        // case 'CHANGE':
        //     return state + (action.payload.direction == 'inc' ? action.payload.step : -action.payload.step);
        case 'INCREMENT':
            // return Object.assign({}, state, {counter: state.counter + 1});
            return {...state, counter: state.counter + state.step};
        case 'CHANGE_STEP':
            return {...state, step: action.payload};
        case 'LOGOUT': 
            return initialState;
        default:
            return state;
    }
};

export default counter;