import { useEffect } from 'react';
import { connect } from 'react-redux';
import { fetchStarWarsCharacters, increaseCharacterPower } from '../../actions/starwarsActions';
import { Link } from 'react-router-dom'
import { Table } from 'antd';
import { getStarwarsCharacters } from '../../reducers';

const Starwars = ({
    characters,
    fetchStarWarsCharacters,
    increaseCharacterPower,
}) => {
    useEffect(() => {
        fetchStarWarsCharacters()
    }, [])

    const TABLE_COLUMNS = [
        {
            title: 'Id',
            dataIndex: 'id',
            key: 'id',
        },
        {
            title: 'Name',
            dataIndex: 'name',
            key: 'name',
            render: (text, row) => <Link to={`/starwars/characters/${row.id}`}>{text}</Link>,
        },
        {
            title: 'Power',
            dataIndex: 'power',
            key: 'power',
            sorter: {
                compare: (a, b) =>  b.power - a.power,
            },
        },
        {
            title: 'Operations',
            dataIndex: 'operations',
            key: 'operations',
            render: function (_, row, index) {
                return (
                    <button onClick={e => increaseCharacterPower(row.id)}>Increase</button>
                );
            }
        }
    ];

    return (
        <Table columns={TABLE_COLUMNS} dataSource={characters} />
    )
};


const mapStateToProps = (state) => ({
    characters: getStarwarsCharacters(state)
});

const mapDispatchToProps = {
    fetchStarWarsCharacters,
    increaseCharacterPower,
};

export default connect(mapStateToProps, mapDispatchToProps)(Starwars);