import starwarsService from '../services/starwarsService';
import { FETCH_CHARACTER, FETCH_CHARACTERS } from './actionTypes';

// Simple Action Creators
const fetchStarWarsCharacterSuccess = (character, characterId) => ({
    type: FETCH_CHARACTER,
    payload: character,
    characterId,
})

const fetchStarWarsCharactersSuccess = (characters) => ({
    type: FETCH_CHARACTERS,
    payload: characters,
})

// Composite Action Creators
export const fetchStarWarsCharacter = (id) => async (dispatch) => {
    let character = await starwarsService.getCharacter(id);

    dispatch(fetchStarWarsCharacterSuccess(character, id));
}


export const fetchStarWarsCharacters = () => async (dispatch) => {
    try {
        let characters = await starwarsService.getCharacters();

        characters = characters.map((x, i) => ({id: i + 1, name: x.name}))

        dispatch(fetchStarWarsCharactersSuccess(characters));
    } catch (err) {
        console.log(err);
    }
}; 

export const increaseCharacterPower = (id) => ({
    type: 'CHARACTER_INCREASE_POWER',
    characterId: id
});