import { useRef, useContext } from 'react';
import './Home.scss';
import { Link } from 'react-router-dom';
import useForm from '../../hooks/useForm';
import UserContext from '../../contexts/UserContext';

const Home = (props) => {
    const [values, setValues] = useForm({ name: '', bio: '' });
    const [userState, dispatch] = useContext(UserContext);
    const formSubmitRef = useRef();

    const onNewsletterSendClick = (e) => {
        console.log('form is created by ivaylo');

        dispatch({
            type: 'USER_FORM_SUBMITED',
            payload: values,
        })
    };

    const handleCheckboxClick = (e) => {
        dispatch({
            type: 'CHANGE_ONLINE',
            payload: e.target.checked
        });
    }

    return (
        <section className="newsletter">
            <button ref={formSubmitRef} type="button" onClick={onNewsletterSendClick}>Send</button>

            <h1>This is body</h1>
            <Link to="test">Test</Link>
            <form>
                <div style={{ border: '1px solid red' }}>
                    <label htmlFor="username">Title</label>
                    <input type="text" name="name" id="username" onChange={setValues} />
                </div>

                <div>
                    <label htmlFor="bio">Content</label>
                    <textarea name="bio" id="bio" cols="30" rows="10" onChange={setValues}></textarea>
                </div>

                <div>
                    <label htmlFor="online">Online</label>
                    <input type="checkbox" name="online" onClick={handleCheckboxClick} />
                </div>

                <button type="button" onClick={() => formSubmitRef.current.click()}>Custom Button</button>
            </form>


        </section>
    )
};

export default Home;