import { useReducer } from 'react';
import Header from './components/Header';
import Home from './components/Home';
import { Route, Switch } from "react-router-dom";
import UserContext from './contexts/UserContext';
import Counter from './components/Counter';
import Starwars from './components/Starwars';
import CharacterDetails from './components/Starwars/CharacterDetails';
import { Provider } from 'react-redux';
import store from './utils/store';
import './App.scss';

const userReducer = (state, action) => {
    switch (action.type) {
        case 'CHANGE_ONLINE':
            return { ...state, access: { ...state.access, onLine: action.payload } }
        case 'USER_FORM_SUBMITED':
            return { ...state, name: action.payload.name, bio: action.payload.bio };
        default:
            return state;
    }
};

function App() {
    const initialState = { name: '', bio: '', age: 0, access: { onLine: true, onSight: false }, hobbies: ['sports', 'table-tenis'] };

    const [state, dispatch] = useReducer(userReducer, initialState);

    return (
        <Provider store={store}>
            <UserContext.Provider value={[state, dispatch]}>
                <div className="App">
                    <Header />

                    <Switch>
                        <Route path="/" exact component={Home} />
                        <Route path="/counter" exact component={Counter} />
                        <Route path="/starwars/characters" exact component={Starwars} />
                        <Route path="/starwars/characters/:id" exact component={CharacterDetails} />
                        <Route path="/test">
                            <h1>Test page</h1>
                        </Route>
                    </Switch>
                </div>
            </UserContext.Provider>
        </Provider>
    );
}

export default App;
