import { combineReducers } from 'redux';

import counter from './counterReducer';
import user from './userReducer';
import starwars, * as fromStarwars from './starwarsReducer';

const rootReducer = combineReducers({
    user,
    counter,
    characters: starwars,
});

export default rootReducer;

// Selectors
export const getStarwarsCharacters = (state) => fromStarwars.getStarwarsCharacters(state.characters);
export const getStarwarsCharacter = (state, id) => fromStarwars.getStarwarsCharacter(state.characters, id)
