import { combineReducers } from 'redux';
import {
    FETCH_CHARACTER,
    FETCH_CHARACTERS,
    CHARACTER_INCREASE_POWER
} from '../actions/actionTypes';

const characterBaseInitialState = {
    name: '',
    power: 0,
};

const character = (state = characterBaseInitialState, action) => {
    if (action.characterId != state.id) {
        return state;
    }

    switch (action.type) {
        case FETCH_CHARACTERS:
            return { ...characterBaseInitialState, ...state };
        case FETCH_CHARACTER:
            return { ...state, ...action.payload };
        case CHARACTER_INCREASE_POWER:
            return { ...state, power: state.power + 1 };
        default:
            return state;
    }
};

const characters = (state = [], action) => {
    switch (action.type) {
        case FETCH_CHARACTERS:
            return action.payload.map(x => character(x, { ...action, characterId: x.id }))
        case FETCH_CHARACTER:
        case CHARACTER_INCREASE_POWER:
            return state.map(x => character(x, action));
        default:
            return state;
    }
}

const currentCharacter = (state = {}, action) => {
    switch (action.type) {
        case FETCH_CHARACTER:
            return { ...action.payload };
        default:
            return state;
    }
}

export default combineReducers({
    list: characters,
    current: currentCharacter,
});

export const getStarwarsCharacters = (state) => state.list;
// export const getStarwarsCharacter = (state, id) => state.find(x => x.id == id);
export const getStarwarsCharacter = (state, id) => state.current;
