import { useEffect } from 'react';
import { connect } from 'react-redux';
import { fetchStarWarsCharacter } from '../../../actions/starwarsActions';
import { Card } from 'antd';
import { getStarwarsCharacter } from '../../../reducers'
import './CharacterDetails.scss';
const { Meta } = Card;

const Starwars = ({
    character,
    fetchStarWarsCharacter,
    match,
}) => {
    useEffect(() => {
        fetchStarWarsCharacter(match.params.id)
    }, [])

    return (
        <div className="starwars-character-details">
            <h1>Star Wars Character</h1>
            <Card
                hoverable
                style={{ width: 240 }}
                cover={<img alt="example" src="https://lumiere-a.akamaihd.net/v1/images/star-wars-the-rise-of-skywalker-theatrical-poster-1000_ebc74357.jpeg?region=0%2C0%2C891%2C1372" />}
            >
                <Meta title={`Character #${match.params.id}`} description={character.name} />
            </Card>,
        </div>
    )
};

const mapStateToProps = (state, ownProps) => ({
    character: getStarwarsCharacter(state, ownProps.id) // id is not needed
});

const mapDispatchToProps = {
    fetchStarWarsCharacter
};

export default connect(mapStateToProps, mapDispatchToProps)(Starwars);